(4674, 'Talent over Privilege', NULL, NULL, NULL, NULL, 0, 'mission-heading', 'welcome'),
(4675, 'Live from Miami Tower 20, ONSITES High School provides a fully U.S. High School Diploma that is globally accessible to every determined student – regardless of background or borders. In a fair and transparent environment, every student’s full potential is unlocked, independence and future-ready skills are built, and parents receive clear, reliable guidance.', NULL, NULL, NULL, NULL, 0, 'mission-content', 'welcome'),
(4676, 'What Sets Us Apart', NULL, NULL, NULL, NULL, 0, 'benefits-heading', 'welcome'),
(4677, 'We don’t make you fit the system. We built the system around talent that refuses to wait.', NULL, NULL, NULL, NULL, 0, 'benefits-content', 'welcome'),
(4678, 'Florida-Recognized High School', NULL, NULL, NULL, NULL, 0, 'benefits-box-1', 'welcome'),
(4679, 'Rolling Enrollment – Start Any Day', NULL, NULL, NULL, NULL, 0, 'benefits-box-2', 'welcome'),
(4680, '12-Month Cross-Grade Learning', NULL, NULL, NULL, NULL, 0, 'benefits-box-3', 'welcome'),
(4681, 'Credit Transfer up to 75% ', NULL, NULL, NULL, NULL, 0, 'benefits-box-4', 'welcome'),
(4682, 'ONSITES High School Florida: Absolutely Exclusive & Radically Open', NULL, NULL, NULL, NULL, 0, 'about-heading', 'welcome'),
(4683, '<p>20th Floor, Miami Tower.</p>\n        <p>From up here, the view stretches beyond the Miami skyline – into the world.</p>\n\n        <p>An American high school diploma that can open doors worldwide does not belong to any particular background. It belongs to those who have what it takes.</p>\n\n        <p>Equal opportunity is not an empty phrase, but lived reality – locally and internationally. Every talented young person finds their place – without differences, without barriers.</p>\n\n        <p>Real innovation pulses through every school day, and genuine solidarity shapes every interaction.</p>\n\n        <p>Everyone is welcome. Everyone is seen. Everyone can unfold their full potential within a supportive community.</p>\n\n        <p>At this height, something rare emerges: a place that is radically open – and precisely for that reason absolutely exclusive.</p>\n        This is transformation.\n\n        <p>ONSITES High School.</p>\n\n        <p>Not for everyone.</p>\n\n        <p>But for everyone who belongs here.</p>', NULL, NULL, NULL, '<p>20th Floor, Miami Tower.</p>\n        <p>From up here, the view stretches beyond the Miami skyline – into the world.</p>\n\n        <p>An American high school diploma that can open doors worldwide does not belong to any particular background. It belongs to those who have what it takes.</p>\n\n        <p>Equal opportunity is not an empty phrase, but lived reality – locally and internationally. Every talented young person finds their place – without differences, without barriers.</p>\n\n        <p>Real innovation pulses through every school day, and genuine solidarity shapes every interaction.</p>\n\n        <p>Everyone is welcome. Everyone is seen. Everyone can unfold their full potential within a supportive community.</p>\n\n        <p>At this height, something rare emerges: a place that is radically open – and precisely for that reason absolutely exclusive.</p>\n        This is transformation.\n\n        <p>ONSITES High School.</p>\n\n        <p>Not for everyone.</p>\n\n        <p>But for everyone who belongs here.</p>', 1, 'about-content', 'welcome'),
